/** Wrap response promise with duration logging. */
function logResponse(
	responsePromise: Promise<Response>,
	start: number,
	method: string,
	path: string,
	shouldLog: boolean
): Promise<Response> {
	if (!shouldLog) return responsePromise;

	return responsePromise.then((response) => {
